{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class PropertyNamingRuleMutableCollectionTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given an object with a mutable collection property then do not emit`() {
        val code =
            """
            object Foo {
                val someMap: MutableMap<String, String> = mutableMapOf()
                val someList: MutableList<String> = mutableListOf()
                val someSet: MutableSet<String> = mutableSetOf()
                val someIterable: MutableIterable<String> = mutableListOf()
                val someCollection: MutableCollection<String> = mutableListOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a companion object with a mutable collection property then do not emit`() {
        val code =
            """
            class Foo {
                companion object {
                    val someMap: MutableMap<String, String> = mutableMapOf()
                }
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top level mutable collection property then do not emit`() {
        val code =
            """
            val someMap: MutableMap<String, String> = mutableMapOf()
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}
